import {
    BrowserRouter,
    Routes,
    Route
}

from "react-router-dom";

import Home
from "./pages/Home";

import BookingPage
from "./pages/BookingPage";

import RegisterPage
from "./pages/RegisterPage";

import LoginPage
from "./pages/LoginPage";

import MyBookings
from "./pages/MyBookings";

import AdminDashboard
from "./pages/AdminDashboard";

import AdminLogin
from "./pages/AdminLogin";

import ProfilePage
from "./pages/ProfilePage";

import Navbar
from "./components/Navbar";

import ProtectedRoute
from "./components/ProtectedRoute";

import AdminProtectedRoute
from "./components/AdminProtectedRoute";

function App() {

    return (

        <BrowserRouter>

            <Navbar />

            <Routes>

                <Route
                    path="/"

                    element={<Home />}
                />

                <Route
                    path="/register"

                    element={
                        <RegisterPage />
                    }
                />

                <Route
                    path="/login"

                    element={
                        <LoginPage />
                    }
                />

                <Route
                    path="/admin-login"

                    element={
                        <AdminLogin />
                    }
                />

                <Route
                    path="/booking/:id"

                    element={

                        <ProtectedRoute>

                            <BookingPage />

                        </ProtectedRoute>
                    }
                />

                <Route
                    path="/my-bookings"

                    element={

                        <ProtectedRoute>

                            <MyBookings />

                        </ProtectedRoute>
                    }
                />

                <Route
                    path="/profile"

                    element={

                        <ProtectedRoute>

                            <ProfilePage />

                        </ProtectedRoute>
                    }
                />

                <Route
                    path="/admin-dashboard"

                    element={

                        <AdminProtectedRoute>

                            <AdminDashboard />

                        </AdminProtectedRoute>
                    }
                />

            </Routes>

        </BrowserRouter>
    );
}

export default App;
